// DFS with backtracking
function countPaths(grid) {
  const rows = grid.length, cols = grid[0].length;
  const visited = new Set();
  function dfs(r, c) {
    if (r < 0 || c < 0 || r >= rows || c >= cols || grid[r][c] === 1 || visited.has(`${r},${c}`)) return 0;
    if (r === rows-1 && c === cols-1) return 1;
    visited.add(`${r},${c}`);
    const count = dfs(r+1,c) + dfs(r-1,c) + dfs(r,c+1) + dfs(r,c-1);
    visited.delete(`${r},${c}`);
    return count;
  }
  return dfs(0, 0);
}
